I think this was removed because you can't set missing fields with validate_assignment=True, but I would suggest we add a test of the new behavior:
```python
def test_validate_assignment_extra_missing_fields():
    @pydantic.dataclasses.dataclass(config=dict(validate_assignment=True), frozen=False)
    class MyDataclass:
        a: int

    d = MyDataclass(1)
    assert d.a == 1

    with pytest.raises(ValidationError) as exc_info:
        d.extra_field = 1.23
    assert exc_info.value.errors() == [
        {
            'ctx': {'attribute': 'extra_field'},
            'input': 1.23,
            'loc': ('extra_field',),
            'msg': "Object has no attribute 'extra_field'",
            'type': 'no_such_attribute',
        }
    ]
